package com.fuck.snooping;

import android.app.Activity;
import android.content.ComponentName;
import android.content.Context;
import android.content.ContextWrapper;
import android.content.Intent;
import android.view.MotionEvent;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;

import java.util.Arrays;
import java.util.HashSet;

import de.robv.android.xposed.IXposedHookLoadPackage;
import de.robv.android.xposed.XC_MethodHook;
import de.robv.android.xposed.XC_MethodReplacement;
import de.robv.android.xposed.XposedBridge;
import de.robv.android.xposed.XposedHelpers;
import de.robv.android.xposed.callbacks.XC_LoadPackage.LoadPackageParam;

public class AntiSnoopingHook implements IXposedHookLoadPackage {

    private static final String TAG = "AntiSnooping: ";
    private static final String WECHAT_PACKAGE = "com.tencent.mm";
    private static final String SELF_PACKAGE = "com.fuck.snooping";

    private static final String IMPROVE_SNS_UI = "com.tencent.mm.plugin.sns.ui.Improve.ImproveSnsTimelineUI";
    private static final String SNS_TIME_LINE_UI = "com.tencent.mm.plugin.sns.ui.SnsTimeLineUI";
    private static final String LAUNCHER_UI = "com.tencent.mm.ui.LauncherUI";

    private static final HashSet<String> TARGET_ACTIVITIES = new HashSet<>(Arrays.asList(
            IMPROVE_SNS_UI,
            SNS_TIME_LINE_UI,
            "com.tencent.mm.plugin.sns.ui.SnsUserUI",
            "com.tencent.mm.plugin.sns.ui.SnsMsgUI",
            "com.tencent.mm.plugin.sns.ui.SnsCommentDetailUI",
            "com.tencent.mm.plugin.sns.ui.SnsGalleryUI"
    ));

    @Override
    public void handleLoadPackage(final LoadPackageParam lpparam) throws Throwable {

        if (SELF_PACKAGE.equals(lpparam.packageName)) {
            try {
                XposedHelpers.findAndHookMethod(
                        "com.fuck.snooping.ModuleStatus",
                        lpparam.classLoader,
                        "isActivated",
                        XC_MethodReplacement.returnConstant(true)
                );
            } catch (Throwable t) {
                XposedBridge.log(TAG + "Self-hook failed: " + t.getMessage());
            }
            return;
        }

        if (WECHAT_PACKAGE.equals(lpparam.packageName)) {
            XposedBridge.log(TAG + "WeChat detected, initializing nuclear interception...");

            // 【终极大招 1】View 抹杀：在 View 布局或刷新时，强制隐藏敏感关键字 View
            try {
                XposedHelpers.findAndHookMethod(
                        View.class,
                        "onLayout",
                        boolean.class, int.class, int.class, int.class, int.class,
                        new XC_MethodHook() {
                            @Override
                            protected void afterHookedMethod(MethodHookParam param) throws Throwable {
                                View view = (View) param.thisObject;
                                if (view == null) return;

                                if (hasTargetKeywordSimple(view, "朋友圈") || hasTargetKeywordSimple(view, "相册")) {
                                    // 检查 context 确认不是聊天页面的文字（此处可进一步优化，但先上核弹）
                                    Activity activity = getActivityFromView(view);
                                    if (activity != null && LAUNCHER_UI.equals(activity.getClass().getName())) {
                                        view.setVisibility(View.GONE);
                                        view.setEnabled(false);
                                        view.setClickable(false);
                                    }
                                }
                            }
                        }
                );
            } catch (Throwable t) {
                XposedBridge.log(TAG + "Nuclear Strategy 1 failed: " + t.getMessage());
            }

            // 【终极大招 2】全局触摸劫持：检测到点击位置含有敏感词时，直接吞掉事件
            try {
                XposedHelpers.findAndHookMethod(
                        Activity.class,
                        "dispatchTouchEvent",
                        MotionEvent.class,
                        new XC_MethodHook() {
                            @Override
                            protected void beforeHookedMethod(MethodHookParam param) throws Throwable {
                                MotionEvent event = (MotionEvent) param.args[0];
                                if (event.getAction() == MotionEvent.ACTION_DOWN) {
                                    Activity activity = (Activity) param.thisObject;
                                    if (activity == null) return;

                                    View decorView = activity.getWindow().getDecorView();
                                    View hitView = findViewAt(decorView, (int)event.getRawX(), (int)event.getRawY());

                                    if (hitView != null && (hasTargetKeywordSimple(hitView, "朋友圈") || hasTargetKeywordSimple(hitView, "相册"))) {
                                        if (LAUNCHER_UI.equals(activity.getClass().getName())) {
                                            XposedBridge.log(TAG + "Touch Hijack: Blocked click on sensitive area.");
                                            param.setResult(true); // 吞掉事件
                                        }
                                    }
                                }
                            }
                        }
                );
            } catch (Throwable t) {
                XposedBridge.log(TAG + "Nuclear Strategy 2 failed: " + t.getMessage());
            }

            // 【拦截点 3】阻止 startActivity (从 LauncherUI 进入朋友圈)
            try {
                XposedHelpers.findAndHookMethod(
                        Activity.class,
                        "startActivity",
                        Intent.class,
                        new XC_MethodHook() {
                            @Override
                            protected void beforeHookedMethod(MethodHookParam param) throws Throwable {
                                Intent intent = (Intent) param.args[0];
                                if (intent == null) return;

                                ComponentName component = intent.getComponent();
                                String targetClass = component != null ? component.getClassName() : "";

                                if (IMPROVE_SNS_UI.equals(targetClass) || SNS_TIME_LINE_UI.equals(targetClass)) {
                                    XposedBridge.log(TAG + "Blocking transition to SNS: " + targetClass);
                                    param.setResult(null);
                                }
                            }
                        }
                );
            } catch (Throwable t) {
                XposedBridge.log(TAG + "startActivity hook failed: " + t.getMessage());
            }

            // 【拦截点 4】onResume 强力清理
            try {
                XposedHelpers.findAndHookMethod(
                        Activity.class,
                        "onResume",
                        new XC_MethodHook() {
                            @Override
                            protected void afterHookedMethod(MethodHookParam param) throws Throwable {
                                Activity activity = (Activity) param.thisObject;
                                if (activity == null) return;

                                String className = activity.getClass().getName();
                                if (TARGET_ACTIVITIES.contains(className)) {
                                    XposedBridge.log(TAG + "onResume Force Exit: " + className);
                                    activity.finish();
                                    return;
                                }

                                View decorView = activity.getWindow().getDecorView();
                                if (hasTargetKeyword(decorView, "朋友圈相册")) {
                                    XposedBridge.log(TAG + "Content Intercept onResume: finishing.");
                                    activity.finish();
                                }
                            }
                        }
                );
            } catch (Throwable t) {
                XposedBridge.log(TAG + "onResume hook failed: " + t.getMessage());
            }
        }
    }

    private boolean hasTargetKeywordSimple(View view, String keyword) {
        if (view instanceof TextView) {
            CharSequence text = ((TextView) view).getText();
            return text != null && text.toString().contains(keyword);
        }
        CharSequence contentDesc = view.getContentDescription();
        return contentDesc != null && contentDesc.toString().contains(keyword);
    }

    private boolean hasTargetKeyword(View view, String keyword) {
        if (hasTargetKeywordSimple(view, keyword)) return true;
        if (view instanceof ViewGroup) {
            ViewGroup group = (ViewGroup) view;
            int childCount = group.getChildCount();
            for (int i = 0; i < childCount; i++) {
                if (hasTargetKeyword(group.getChildAt(i), keyword)) {
                    return true;
                }
            }
        }
        return false;
    }

    private View findViewAt(View view, int x, int y) {
        int[] location = new int[2];
        view.getLocationOnScreen(location);
        int left = location[0];
        int top = location[1];
        int right = left + view.getWidth();
        int bottom = top + view.getHeight();

        if (x >= left && x <= right && y >= top && y <= bottom) {
            if (view instanceof ViewGroup) {
                ViewGroup group = (ViewGroup) view;
                for (int i = group.getChildCount() - 1; i >= 0; i--) {
                    View child = group.getChildAt(i);
                    View found = findViewAt(child, x, y);
                    if (found != null) return found;
                }
            }
            return view;
        }
        return null;
    }

    private Activity getActivityFromView(View view) {
        if (view == null) return null;
        Context context = view.getContext();
        while (context instanceof ContextWrapper) {
            if (context instanceof Activity) {
                return (Activity) context;
            }
            context = ((ContextWrapper) context).getBaseContext();
        }
        return null;
    }
}

package com.fuck.snooping;

import android.app.Activity;
import android.content.ComponentName;
import android.content.Context;
import android.content.ContextWrapper;
import android.content.Intent;
import android.view.MotionEvent;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;

import java.util.Arrays;
import java.util.HashSet;

import de.robv.android.xposed.IXposedHookLoadPackage;
import de.robv.android.xposed.XC_MethodHook;
import de.robv.android.xposed.XC_MethodReplacement;
import de.robv.android.xposed.XposedBridge;
import de.robv.android.xposed.XposedHelpers;
import de.robv.android.xposed.callbacks.XC_LoadPackage.LoadPackageParam;

public class AntiSnoopingHook implements IXposedHookLoadPackage {

    private static final String TAG = "AntiSnooping: ";
    private static final String WECHAT_PACKAGE = "com.tencent.mm";
    private static final String SELF_PACKAGE = "com.fuck.snooping";

    private static final String IMPROVE_SNS_UI = "com.tencent.mm.plugin.sns.ui.Improve.ImproveSnsTimelineUI";
    private static final String SNS_TIME_LINE_UI = "com.tencent.mm.plugin.sns.ui.SnsTimeLineUI";
    private static final String LAUNCHER_UI = "com.tencent.mm.ui.LauncherUI";

    private static final HashSet<String> TARGET_ACTIVITIES = new HashSet<>(Arrays.asList(
            IMPROVE_SNS_UI,
            SNS_TIME_LINE_UI,
            "com.tencent.mm.plugin.sns.ui.SnsUserUI",
            "com.tencent.mm.plugin.sns.ui.SnsMsgUI",
            "com.tencent.mm.plugin.sns.ui.SnsCommentDetailUI",
            "com.tencent.mm.plugin.sns.ui.SnsGalleryUI"
    ));

    // sensitive keywords centralized
    private static final String[] SENSITIVE_KEYWORDS = new String[]{"朋友圈", "相册"};

    @Override
    public void handleLoadPackage(final LoadPackageParam lpparam) throws Throwable {

        if (SELF_PACKAGE.equals(lpparam.packageName)) {
            try {
                XposedHelpers.findAndHookMethod(
                        "com.fuck.snooping.ModuleStatus",
                        lpparam.classLoader,
                        "isActivated",
                        XC_MethodReplacement.returnConstant(true)
                );
            } catch (Throwable t) {
                XposedBridge.log(TAG + "Self-hook failed: " + t.getMessage());
            }
            return;
        }

        if (WECHAT_PACKAGE.equals(lpparam.packageName)) {
            XposedBridge.log(TAG + "WeChat detected, initializing nuclear interception...");

            // 【终极大招 1】View 抹杀：在 View 布局或刷新时，强制隐藏敏感关键字 View
            try {
                XposedHelpers.findAndHookMethod(
                        View.class,
                        "onLayout",
                        boolean.class, int.class, int.class, int.class, int.class,
                        new XC_MethodHook() {
                            @Override
                            protected void afterHookedMethod(MethodHookParam param) throws Throwable {
                                View view = (View) param.thisObject;
                                if (view == null) return;

                                Activity activity = getActivityFromView(view);
                                scanAndDisable(view, activity);
                            }
                        }
                );
            } catch (Throwable t) {
                XposedBridge.log(TAG + "View onLayout hook failed: " + t.getMessage());
            }

            // 【终极大招 2】全局触摸劫持：检测到点击位置含有敏感词时，直接吞掉事件
            try {
                XposedHelpers.findAndHookMethod(
                        Activity.class,
                        "dispatchTouchEvent",
                        MotionEvent.class,
                        new XC_MethodHook() {
                            @Override
                            protected void beforeHookedMethod(MethodHookParam param) throws Throwable {
                                MotionEvent event = (MotionEvent) param.args[0];
                                if (event.getAction() == MotionEvent.ACTION_DOWN) {
                                    Activity activity = (Activity) param.thisObject;
                                    if (activity == null) return;

                                    View decorView = activity.getWindow().getDecorView();
                                    View hitView = findViewAt(decorView, (int)event.getRawX(), (int)event.getRawY());

                                    if (hitView != null && isSensitiveView(hitView)) {
                                        if (LAUNCHER_UI.equals(activity.getClass().getName())) {
                                            XposedBridge.log(TAG + "Touch Hijack: Blocked click on sensitive area.");
                                            disableSensitiveView(hitView);
                                            param.setResult(true); // swallow event
                                        }
                                    }
                                }
                            }
                        }
                );
            } catch (Throwable t) {
                XposedBridge.log(TAG + "Touch hook failed: " + t.getMessage());
            }

            // 【拦截点 3】阻止 startActivity (从 LauncherUI 进入朋友圈)
            try {
                XposedHelpers.findAndHookMethod(
                        Activity.class,
                        "startActivity",
                        Intent.class,
                        new XC_MethodHook() {
                            @Override
                            protected void beforeHookedMethod(MethodHookParam param) throws Throwable {
                                Intent intent = (Intent) param.args[0];
                                if (intent == null) return;

                                if (shouldBlockIntent(intent)) {
                                    XposedBridge.log(TAG + "Blocking transition to SNS via Intent: " + intent);
                                    param.setResult(null);
                                }
                            }
                        }
                );

                // also hook Context.startActivity to catch other paths
                XposedHelpers.findAndHookMethod(
                        Context.class,
                        "startActivity",
                        Intent.class,
                        new XC_MethodHook() {
                            @Override
                            protected void beforeHookedMethod(MethodHookParam param) throws Throwable {
                                Intent intent = (Intent) param.args[0];
                                if (intent == null) return;
                                if (shouldBlockIntent(intent)) {
                                    XposedBridge.log(TAG + "Blocking transition to SNS via Context.startActivity: " + intent);
                                    param.setResult(null);
                                }
                            }
                        }
                );
            } catch (Throwable t) {
                XposedBridge.log(TAG + "startActivity hooks failed: " + t.getMessage());
            }

            // 【拦截点 4】onResume 强力清理
            try {
                XposedHelpers.findAndHookMethod(
                        Activity.class,
                        "onResume",
                        new XC_MethodHook() {
                            @Override
                            protected void afterHookedMethod(MethodHookParam param) throws Throwable {
                                Activity activity = (Activity) param.thisObject;
                                if (activity == null) return;

                                String className = activity.getClass().getName();
                                if (TARGET_ACTIVITIES.contains(className)) {
                                    XposedBridge.log(TAG + "onResume Force Exit: " + className);
                                    activity.finish();
                                    return;
                                }

                                View decorView = activity.getWindow().getDecorView();
                                scanAndDisable(decorView, activity);
                            }
                        }
                );
            } catch (Throwable t) {
                XposedBridge.log(TAG + "onResume hook failed: " + t.getMessage());
            }
        }
    }

    // Helper: determine if a view (or its children) contain sensitive keywords
    private boolean isSensitiveView(View view) {
        if (view == null) return false;
        if (view instanceof TextView) {
            CharSequence text = ((TextView) view).getText();
            if (text != null) {
                String s = text.toString();
                for (String kw : SENSITIVE_KEYWORDS) {
                    if (s.contains(kw)) return true;
                }
            }
        }
        CharSequence cd = view.getContentDescription();
        if (cd != null) {
            String s = cd.toString();
            for (String kw : SENSITIVE_KEYWORDS) {
                if (s.contains(kw)) return true;
            }
        }
        if (view instanceof ViewGroup) {
            ViewGroup g = (ViewGroup) view;
            int cc = g.getChildCount();
            for (int i = 0; i < cc; i++) {
                if (isSensitiveView(g.getChildAt(i))) return true;
            }
        }
        return false;
    }

    // Helper: disable clicking on view while keeping appearance
    private void disableSensitiveView(View view) {
        if (view == null) return;
        try {
            view.setClickable(false);
            view.setEnabled(false);
            // remove typical listeners
            try {
                view.setOnClickListener(null);
            } catch (Throwable ignored) {}
            try {
                view.setOnTouchListener(null);
            } catch (Throwable ignored) {}
            // do not change visibility to keep appearance
        } catch (Throwable t) {
            XposedBridge.log(TAG + "disableSensitiveView error: " + t.getMessage());
        }
    }

    // Recursively scan a view and disable any sensitive subviews.
    // If activity is LauncherUI, we perform stricter disabling (disable clickable)
    private void scanAndDisable(View view, Activity activity) {
        if (view == null) return;
        if (isSensitiveView(view)) {
            // only disable clickable behavior, keep UI as-is
            disableSensitiveView(view);
        }
        if (view instanceof ViewGroup) {
            ViewGroup g = (ViewGroup) view;
            for (int i = 0; i < g.getChildCount(); i++) {
                scanAndDisable(g.getChildAt(i), activity);
            }
        }
    }

    // Centralized intent check: block intents that target known SNS activities
    private boolean shouldBlockIntent(Intent intent) {
        if (intent == null) return false;
        ComponentName component = intent.getComponent();
        if (component != null) {
            String cls = component.getClassName();
            if (IMPROVE_SNS_UI.equals(cls) || SNS_TIME_LINE_UI.equals(cls)) return true;
        }
        // check extras or data for class names (best-effort)
        try {
            if (intent.getStringExtra("target_class") != null) {
                String tc = intent.getStringExtra("target_class");
                if (IMPROVE_SNS_UI.equals(tc) || SNS_TIME_LINE_UI.equals(tc)) return true;
            }
        } catch (Throwable ignored) {}
        // fallback: check action or data string for keywords
        String action = intent.getAction();
        if (action != null && (action.contains("sns") || action.contains("Sns"))) return true;
        return false;
    }

    private View findViewAt(View view, int x, int y) {
        int[] location = new int[2];
        view.getLocationOnScreen(location);
        int left = location[0];
        int top = location[1];
        int right = left + view.getWidth();
        int bottom = top + view.getHeight();

        if (x >= left && x <= right && y >= top && y <= bottom) {
            if (view instanceof ViewGroup) {
                ViewGroup group = (ViewGroup) view;
                for (int i = group.getChildCount() - 1; i >= 0; i--) {
                    View child = group.getChildAt(i);
                    View found = findViewAt(child, x, y);
                    if (found != null) return found;
                }
            }
            return view;
        }
        return null;
    }

    private Activity getActivityFromView(View view) {
        if (view == null) return null;
        Context context = view.getContext();
        while (context instanceof ContextWrapper) {
            if (context instanceof Activity) {
                return (Activity) context;
            }
            context = ((ContextWrapper) context).getBaseContext();
        }
        return null;
    }
}
